// Lookup cascata: 5→4→3 campos
function gfx(b0,b1,b3,b4,b5){
  const m=b1&0x7F;
  return FX_BY_KEY[`${b0},${m},${b3},${b4},${b5}`]
      || FX_BY_KEY[`${b0},${m},${b3},${b4}`]
      || FX_BY_KEY[`${b0},${m},${b3}`]
      || {n:`[${b0}/${m}/${b3}]`,c:'Desconhecido',_unknown:true};
}

