function fxInfo(name){
  if(!name) return null;
  if(FX_DB[name]) return FX_DB[name];
  const nl=name.toLowerCase();
  const k=Object.keys(FX_DB).find(k=>k.toLowerCase()===nl);
  if(k) return FX_DB[k];
  if(name&&name.startsWith('['))
    return{desc:'Efeito nao identificado.',cat:'Desconhecido',
      params:Array.from({length:10},(_,i)=>({n:'P'+(i+1),r:'0-127',d:'Param '+(i+1),min:0,max:127,dflt:0}))};
  return null;
}

